  private _emitter: Emitter<void> | null = null;  // Lazy creation

  cancel() {
    if (!this._isCancelled) {
      this._isCancelled = true;
      if (this._emitter) {
        this._emitter.fire(undefined);  // Notify listeners once
        this.dispose();                  // Then cleanup
      }
    }
  }
}
```

